   146→// FetchReleases handles POST /sources/{id}/poll — polls upstream for new
   147→// releases, ingests them, and updates last_polled_at.
   148→func (h *SourcesHandler) FetchReleases(w http.ResponseWriter, r *http.Request) {
   149→	id := r.PathValue("id")
   150→	if id == "" {
   151→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid source ID")
   152→		return
   153→	}
   154→	src, err := h.store.GetSource(r.Context(), id)
   155→	if err != nil {
   156→		RespondError(w, r, http.StatusNotFound, "not_found", "Source not found")
   157→		return
   158→	}
   159→
   160→	ingestionSrc := ingestion.BuildSource(h.httpClient, src.ID, src.Provider, src.Repository)
   161→	if ingestionSrc == nil {
   162→		RespondError(w, r, http.StatusUnprocessableEntity, "unsupported_provider", "Unsupported provider: "+src.Provider)
   163→		return
   164→	}
   165→
   166→	results, err := ingestionSrc.FetchNewReleases(r.Context())
   167→	if err != nil {
   168→		slog.Error("fetch releases failed", "source", src.ID, "err", err)
   169→		_ = h.store.UpdateSourcePollStatus(r.Context(), src.ID, err)
   170→		RespondError(w, r, http.StatusBadGateway, "upstream_error", "Failed to fetch releases from upstream")
   171→		return
   172→	}
   173→
   174→	_ = h.store.UpdateSourcePollStatus(r.Context(), src.ID, nil)
   175→
   176→	newCount := 0
   177→	if len(results) > 0 && h.ingestionService != nil {
   178→		for _, result := range results {
   179→			if procErr := h.ingestionService.ProcessResults(r.Context(), src.ID, src.Provider, []ingestion.IngestionResult{result}); procErr != nil {
   180→				slog.Error("process release failed", "source", src.ID, "version", result.RawVersion, "err", procErr)
