   205→		_ = h.store.UpdateSourcePollStatus(ctx, sourceID, err)
   206→		return
   207→	}
   208→
   209→	_ = h.store.UpdateSourcePollStatus(ctx, sourceID, nil)
   210→
   211→	if len(results) > 0 && h.ingestionService != nil {
   212→		for _, result := range results {
   213→			if procErr := h.ingestionService.ProcessResults(ctx, sourceID, provider, []ingestion.IngestionResult{result}); procErr != nil {
