    11→type Middleware func(http.Handler) http.Handler
    12→
    13→func Chain(mws ...Middleware) Middleware {
    14→	return func(final http.Handler) http.Handler {
    15→		for i := len(mws) - 1; i >= 0; i-- {
    16→			final = mws[i](final)
    17→		}
    18→		return final
    19→	}
    20→}
    21→
    22→func RequestID(next http.Handler) http.Handler {
    23→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    24→		id := uuid.New().String()
    25→		w.Header().Set("X-Request-ID", id)
    26→		next.ServeHTTP(w, r.WithContext(withRequestID(r.Context(), id)))
    27→	})
    28→}
    29→
    30→func Logger(next http.Handler) http.Handler {
    31→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    32→		start := time.Now()
    33→		sw := &statusWriter{ResponseWriter: w, status: http.StatusOK}
    34→		next.ServeHTTP(sw, r)
    35→		slog.Info("request",
    36→			"request_id", getRequestID(r.Context()),
    37→			"method", r.Method,
    38→			"path", r.URL.Path,
    39→			"status", sw.status,
    40→			"duration_ms", time.Since(start).Milliseconds(),
    41→		)
    42→	})
    43→}
